$_MODULE['<{PrestashopAPI}prestashop>9cf3cea9fc2559bc3932a1034a8c77bd'] = 'Garder les données à jour automatiquement';
$_MODULE['<{PrestashopAPI}prestashop>70fab415490de4d1c4d958b059ff1cbf'] = 'Le badge vitrine et les chiffres ci-dessus sont lus depuis une copie locale de vos données marketplace, pour que aucun visiteur de votre boutique n\'attende la marketplace. Cette copie s\'actualise à l\'ouverture de cette page. Pour l\'actualiser selon un planning, appelez cette URL depuis une tâche cron, par exemple une fois par heure :';
$_MODULE['<{PrestashopAPI}prestashop>9b4fe89ace5fbb71472cf7a6c3c0ffe9'] = 'Gardez cette URL privée : quiconque la possède peut déclencher une actualisation. Elle change si vous réinstallez le module.';
$_MODULE['<{PrestashopAPI}prestashop>850d45fc61bfd3cd575cbc45addd9529'] = 'Données en cache';
$_MODULE['<{PrestashopAPI}prestashop>058881da8f789da85e445bfd42bdee3c'] = 'Si quelque chose semble incorrect, effacez la copie locale et téléchargez tout à nouveau.';
