$_MODULE['<{PrestashopAPI}prestashop>3b488ade6f134eacce53039c0d3b7908'] = 'Comment ce module fonctionne';
$_MODULE['<{PrestashopAPI}prestashop>2b567533f379fab2c398929de7c99c2e'] = 'D\'où viennent les chiffres';
$_MODULE['<{PrestashopAPI}prestashop>1438971d29f373379a0ca6b9e82f04b0'] = 'Les chiffres marketplace sont téléchargés depuis l\'API Vendeur PrestaShop Addons avec votre propre clé API, et stockés localement. Vos chiffres boutique proviennent de vos commandes valides. Rien n\'est envoyé ailleurs.';
$_MODULE['<{PrestashopAPI}prestashop>e9ac528d46587d227713f545b102975e'] = 'Pourquoi certains produits n\'affichent pas de ventes boutique';
$_MODULE['<{PrestashopAPI}prestashop>3585339aed30ba73e0e738d458cff45e'] = 'Le module doit savoir quel produit de votre catalogue correspond à quel produit sur la marketplace. Il les associe lorsque la référence de votre produit correspond à l\'ID produit marketplace. Si vous utilisez des références différentes, épinglez-les manuellement dans l\'onglet Produits.';
$_MODULE['<{PrestashopAPI}prestashop>53beb26d8bca00f56fbd295fdee83459'] = 'Remboursements';
$_MODULE['<{PrestashopAPI}prestashop>de980f4d92dea658e437fb1a6db084fd'] = 'Les unités remboursées sont soustraites des unités et du chiffre d\'affaires, des deux côtés, pour que les totaux reflètent ce que vous avez réellement conservé.';
$_MODULE['<{PrestashopAPI}prestashop>dfcfc43722eef1eab1e4a12e50a068b1'] = 'Devises';
$_MODULE['<{PrestashopAPI}prestashop>9bd1ea4499517071a96ee0340edeccf5'] = 'Les paiements marketplace sont généralement en euros tandis que votre boutique peut vendre dans une autre devise. Les totaux combinés utilisent le taux de change de votre boutique. Sans taux pour la devise marketplace, les totaux combinés sont masqués plutôt qu\'estimés.';
$_MODULE['<{PrestashopAPI}prestashop>9635c7ca9186a5b541c68c3e54afc07d'] = 'Le badge vitrine';
$_MODULE['<{PrestashopAPI}prestashop>8224e1ccb8232fe6f2ccd4fbeb8c2374'] = 'Optionnellement, les pages produit de votre propre boutique peuvent afficher combien de fois un produit a été téléchargé, comme preuve sociale. Issu de la copie locale de vos données, sans temps de chargement supplémentaire, et masqué sous le seuil que vous définissez.';
$_MODULE['<{PrestashopAPI}prestashop>44877c6aa8e93fa5a91c9361211464fb'] = 'Vitesse';
$_MODULE['<{PrestashopAPI}prestashop>803e2b0d8f5afc76e2e54fad606490c0'] = 'Une période de rapport large signifie plus de lignes à télécharger. Si l\'actualisation semble lente, réduisez la période ou allongez l\'intervalle dans les Paramètres.';
$_MODULE['<{PrestashopAPI}prestashop>8b9c1abd043bde61211bc6d58be58370'] = 'Si quelque chose ne fonctionne pas';
$_MODULE['<{PrestashopAPI}prestashop>f2cb075d74e523731af10acbb1177695'] = 'Votre serveur n\'a pas pu ouvrir une connexion HTTPS sortante vers la marketplace. L\'hébergement mutualisé bloque souvent cela. La liste Statut de l\'onglet Tableau de bord indique si cURL est disponible ; si oui, demandez à votre hébergeur si les connexions sortantes vers api.addons.prestashop.com sont autorisées.';
$_MODULE['<{PrestashopAPI}prestashop>f64dc4589dc99c8b6633332d2cd64673'] = 'Générez une nouvelle clé dans votre compte vendeur, sous Paramètres puis API, et collez-la à nouveau. Copiez uniquement la clé, pas le texte autour.';
$_MODULE['<{PrestashopAPI}prestashop>e42e9d958504c5158fe91c5d56ee6214'] = 'Les chiffres sont plus anciens qu\'ils ne devraient l\'être';
$_MODULE['<{PrestashopAPI}prestashop>cce5ffc741270470dec823a4fff75552'] = 'Les ventes boutique sont nulles pour chaque produit';
$_MODULE['<{PrestashopAPI}prestashop>95dab330ce5b2c1d94467c07916fea17'] = 'Aucun de vos produits marketplace n\'a été associé à un produit de votre catalogue. Vérifiez la liste Statut de l\'onglet Tableau de bord, et épinglez les produits manuellement dans l\'onglet Produits.';
$_MODULE['<{PrestashopAPI}prestashop>e67411c887a32a48389e48e21d409fca'] = 'Ce que renvoie l\'API';
$_MODULE['<{PrestashopAPI}prestashop>9d0b331fa4855d2fc2b8ffca416cc545'] = 'La marketplace ne documente que ses produits et données de ventes. Tout le reste, y compris conversations, factures et paiements, est lu depuis des champs dont nous avons dû déduire les noms. Ceci montre une ligne réelle de chaque endpoint de votre propre compte, pour adapter le module à ce que votre compte envoie réellement.';
$_MODULE['<{PrestashopAPI}prestashop>8c97b6869b7a8ca6c4d6ec89ea13cbe0'] = 'Ce sont des données en direct de votre compte vendeur et peuvent contenir des noms ou adresses e-mail d\'acheteurs. Supprimez toute information personnelle avant de les partager.';
